"use client";

import React, { useState } from "react";
import Header from "@/components/Header";
import ProductCard from "@/components/ProductCard";
import CartSidebar from "@/components/CartSidebar";
import PromoBanners from "@/components/PromoBanners";
import { products } from "@/components/data";

export interface CartItem {
 id: number;
 name: string;
 image: string;
 price: number;
 oldPrice?: number;
 quantity: number;
}

export default function Home() {
 const [cart, setCart] = useState<CartItem[]>([]);

 const addToCart = (product: typeof products[0]) => {
  setCart((prev) => {
   const found = prev.find((i) => i.id === product.id);
   if (found) return prev.map((i) => i.id === product.id ? { ...i, quantity: i.quantity + 1 } : i);
   return [
    ...prev,
    {
     id: product.id,
     name: product.name,
     image: product.image ?? "",
     price: product.price,
     oldPrice: product.oldPrice,
     quantity: 1,
    },
   ];
  });
 };

 const updateQty = (id: number, delta: number) => {
  setCart((prev) =>
   prev
    .map((i) => i.id === id ? { ...i, quantity: Math.max(0, i.quantity + delta) } : i)
    .filter((i) => i.quantity > 0)
  );
 };

 const total = cart.reduce((s, i) => s + i.price * i.quantity, 0);

 return (
  <div className="min-h-screen font-manrope" style={{ background: "#F0F0F2" }}>
   <Header />

   <main style={{ display: "flex", maxWidth: "100%", minHeight: "calc(100vh - 68px)" }}>

    {/* ── Left sidebar: plain gray panel ── */}
    <aside
     className="hidden xl:block shrink-0 sticky top-[68px]"
     style={{
      width: "140px",
      height: "calc(100vh - 68px)",
      background: "#E8E8EC",
     }}
    />

    {/* ── Center: banners + products ── */}
    <div
     className="flex-1 min-w-0"
     style={{ padding: "20px 20px 40px 20px", background: "#F0F0F2" }}
    >
     <PromoBanners />

     {/* Section heading */}
     <h2
      style={{
       fontFamily: "var(--font-manrope, sans-serif)",
       fontSize: "20px",
       fontWeight: 800,
       letterSpacing: "-0.025em",
       color: "#1A1A1A",
       marginBottom: "14px",
      }}
     >
      Товары
     </h2>

     {/* Product grid — 5 columns like reference */}
     <div
      style={{
       display: "grid",
       gridTemplateColumns: "repeat(5, 1fr)",
       gap: "1px",
       background: "rgba(0,0,0,0.05)",
       borderRadius: "20px",
       overflow: "hidden",
      }}
     >
      {products.map((p) => (
       <ProductCard
        key={p.id}
        {...p}
        image={p.image ?? ""}
        onAdd={() => addToCart(p)}
       />
      ))}

      {/* "More" tile */}
      <div
       className="ux-p-card flex flex-col items-center justify-center gap-2 cursor-pointer group"
       style={{ minHeight: "180px" }}
      >
       <div
        style={{
         width: "40px",
         height: "40px",
         borderRadius: "50%",
         background: "#F0F0F4",
         display: "flex",
         alignItems: "center",
         justifyContent: "center",
         transition: "transform 0.2s, background 0.2s",
        }}
        className="group-hover:scale-110 group-hover:bg-white"
       >
        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
         <path d="M5 12h14M12 5l7 7-7 7" />
        </svg>
       </div>
       <span
        style={{
         fontFamily: "var(--font-manrope, sans-serif)",
         fontSize: "11px",
         fontWeight: 700,
         color: "#8E8E93",
        }}
       >
        Больше →
       </span>
      </div>
     </div>
    </div>

    {/* ── Right: Cart sidebar ── */}
    <aside
     className="hidden lg:block shrink-0 sticky top-[68px]"
     style={{
      width: "340px",
      height: "calc(100vh - 68px)",
     }}
    >
     <CartSidebar cart={cart} onUpdateQuantity={updateQty} total={total} />
    </aside>
   </main>
  </div>
 );
}
