"use client";
import React, { useState, useEffect } from "react";

const Header = () => {
 const [scrolled, setScrolled] = useState(false);

 useEffect(() => {
  const handleScroll = () => setScrolled(window.scrollY > 10);
  window.addEventListener("scroll", handleScroll, { passive: true });
  return () => window.removeEventListener("scroll", handleScroll);
 }, []);

 return (
  <header
   style={{
    height: "72px",
    position: "sticky",
    top: 0,
    zIndex: 100,
    display: "flex",
    alignItems: "center",
    padding: "0 24px",
    gap: "24px",
    background: scrolled ? "rgba(255,255,255,0.9)" : "#FFFFFF",
    backdropFilter: scrolled ? "blur(20px)" : "none",
    WebkitBackdropFilter: scrolled ? "blur(20px)" : "none",
    borderBottom: "1px solid rgba(0,0,0,0.06)",
    boxShadow: scrolled ? "0 1px 12px rgba(0,0,0,0.06)" : "none",
    transition: "all 0.3s ease",
   }}
  >
   {/* Logo */}
   <div style={{ display: "flex", flexDirection: "column", flexShrink: 0, cursor: "pointer", userSelect: "none" }}>
    <span
     style={{
      fontFamily: "var(--font-manrope, sans-serif)",
      fontSize: "20px",
      fontWeight: 800,
      letterSpacing: "-0.05em",
      lineHeight: "0.88",
      color: "#111111",
     }}
    >
     СМЫСЛ
    </span>
    <span
     style={{
      fontFamily: "var(--font-manrope, sans-serif)",
      fontSize: "20px",
      fontWeight: 800,
      letterSpacing: "-0.05em",
      lineHeight: "0.88",
      color: "#111111",
     }}
    >
     ЕСТЬ
    </span>
   </div>

   {/* Search bar — centered, taking available space */}
   <div style={{ flex: 1, display: "flex", justifyContent: "center" }}>
    <div
     style={{
      display: "flex",
      alignItems: "center",
      gap: "10px",
      background: "#F5F5F7",
      borderRadius: "12px",
      padding: "0 16px",
      height: "42px",
      width: "100%",
      maxWidth: "460px",
      border: "1px solid transparent",
      transition: "all 0.2s",
     }}
     onFocus={(e) => {
      e.currentTarget.style.background = "#fff";
      e.currentTarget.style.borderColor = "#FF375F";
      e.currentTarget.style.boxShadow = "0 0 0 4px rgba(255,55,95,0.08)";
     }}
     onBlur={(e) => {
      e.currentTarget.style.background = "#F5F5F7";
      e.currentTarget.style.borderColor = "transparent";
      e.currentTarget.style.boxShadow = "none";
     }}
    >
     <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#AEAEB2" strokeWidth="2" strokeLinecap="round">
      <circle cx="11" cy="11" r="8" />
      <path d="m21 21-4.35-4.35" />
     </svg>
     <input
      type="text"
      placeholder="Search for croissants, sourdough..."
      style={{
       flex: 1,
       background: "transparent",
       border: "none",
       outline: "none",
       fontFamily: "var(--font-manrope, sans-serif)",
       fontSize: "13px",
       fontWeight: 400,
       color: "#111111",
      }}
     />
    </div>
   </div>

   {/* Profile icon — circle button, right side */}
   <div style={{ flexShrink: 0 }}>
    <button
     style={{
      width: "42px",
      height: "42px",
      borderRadius: "50%",
      background: "#F5F5F7",
      border: "none",
      cursor: "pointer",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      transition: "background 0.2s",
     }}
     onMouseEnter={e => (e.currentTarget.style.background = "#EBEBEF")}
     onMouseLeave={e => (e.currentTarget.style.background = "#F5F5F7")}
    >
     <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#6E6E73" strokeWidth="1.8" strokeLinecap="round">
      <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
      <circle cx="12" cy="7" r="4" />
     </svg>
    </button>
   </div>
  </header>
 );
};

export default Header;
